import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, ProjectContext } from "../../base.ts";

/**
 * 🌀 Dr. Vortex — PhD in Operational Excellence & Algorithm Integrity (TypeScript)
 * Generated by Sovereign Forge.
 */
export class VortexPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "vortex";
        this.name = "Vortex";
        this.emoji = "🌀";
        this.role = "PhD Efficiency Scientist";
        this.phd_identity = "Operational Excellence & Algorithm Integrity (TypeScript)";
        this.stack = "TypeScript";
        this.healingPrompt = "";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js",".tsx"],
            rules: [
          {
                    "regex": "for\\s+.*\\s+in",
                    "issue": "Efficiency: Loop 'for-in' detectado em TS. Verifique se 'for-of' ou métodos funcionais são mais eficientes PhD.",
                    "severity": "low"
          },
          {
                    "regex": "Array\\([1-9][0-9]{4,}\\)",
                    "issue": "Allocation: Alocação de array gigante detectada. Risco de GC pressure PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "while\\s*\\(\\s*true\\s*\\)",
                    "issue": "Complexity: Loop infinito detectado. Garanta que haja sinal de cancelamento PhD.",
                    "severity": "medium"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Vortex operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Vortex, PhD em Operational Excellence & Algorithm Integrity (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
